//! Spec-compliance tests: Hyperlinks (ISO 29500-1 §17.16.22)
//!
//! These tests verify our implementation against specific OOXML hyperlink
//! constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, OpaqueKind};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/hyperlinks";

// ── helpers ──────────────────────────────────────────────────────────────
/// Collect all hyperlink data from a document's paragraphs.
fn collect_hyperlinks(doc: &CanonDoc) -> Vec<stemma::HyperlinkData> {
    let mut out = Vec::new();
    for block in &doc.blocks {
        if let BlockNode::Paragraph(p) = &block.block {
            for inline in p.all_inlines_owned() {
                if let InlineNode::OpaqueInline(opaque) = inline
                    && let OpaqueKind::Hyperlink(data) = opaque.kind
                {
                    out.push(data);
                }
            }
        }
    }
    out
}

// ── external URL ─────────────────────────────────────────────────────────

/// ISO 29500-1 §17.16.22: External hyperlink with r:id should resolve URL
/// from document.xml.rels relationship.
#[test]
fn spec_external_hyperlink_url_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "external-url");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert_eq!(
        link.url,
        Some("https://example.com".to_string()),
        "external hyperlink URL should be resolved from r:id relationship"
    );
}

/// ISO 29500-1 §17.16.22: External hyperlink display text should be extracted
/// from nested runs.
#[test]
fn spec_external_hyperlink_text_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "external-url");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert_eq!(
        link.text, "Click here",
        "hyperlink display text should be extracted from nested runs"
    );
}

// ── internal anchor ──────────────────────────────────────────────────────

/// ISO 29500-1 §17.16.22: Internal hyperlink with w:anchor should populate
/// the anchor field, not the url field.
#[test]
fn spec_internal_anchor_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "internal-anchor");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert_eq!(
        link.anchor,
        Some("bookmark_name".to_string()),
        "internal hyperlink should have anchor='bookmark_name'"
    );
    assert_eq!(link.url, None, "internal hyperlink should not have a url");
}

// ── OpaqueInline with OpaqueKind::Hyperlink ──────────────────────────────

/// ISO 29500-1 §17.16.22: Hyperlinks should produce an OpaqueInline node
/// with OpaqueKind::Hyperlink variant.
#[test]
fn spec_hyperlink_produces_opaque_inline() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "external-url");

    let mut found = false;
    for block in &doc.blocks {
        if let BlockNode::Paragraph(p) = &block.block {
            for inline in p.all_inlines_owned() {
                if let InlineNode::OpaqueInline(opaque) = &inline
                    && matches!(&opaque.kind, OpaqueKind::Hyperlink(_))
                {
                    found = true;
                }
            }
        }
    }
    assert!(
        found,
        "document should contain an OpaqueInline with OpaqueKind::Hyperlink"
    );
}

// ── mixed formatting ─────────────────────────────────────────────────────

/// ISO 29500-1 §17.16.22: Hyperlink with multiple formatted runs should
/// capture the full concatenated display text.
#[test]
fn spec_hyperlink_with_mixed_formatting() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hyperlink-with-formatting");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert_eq!(
        link.text, "bold part and normal part",
        "hyperlink text should be the concatenation of all runs"
    );
}

// ── empty hyperlink ──────────────────────────────────────────────────────

/// ISO 29500-1 §17.16.22: A hyperlink with no nested runs should not crash
/// the parser. It may produce an OpaqueInline with empty text or be filtered.
#[test]
fn spec_hyperlink_empty_does_not_crash() {
    // The main assertion is that this does not panic.
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hyperlink-no-text");

    // Verify the document parsed successfully with at least one paragraph.
    let para_count = doc
        .blocks
        .iter()
        .filter(|b| matches!(&b.block, BlockNode::Paragraph(_)))
        .count();
    assert!(
        para_count >= 1,
        "document should have at least one paragraph"
    );
}

// ── per-run formatting preservation (HyperlinkRun) ───────────────────────

/// ISO 29500-1 §17.16.22 + formatting preservation invariant:
/// Each w:r inside a w:hyperlink must be captured as a separate HyperlinkRun.
/// Domain rule: `runs.len()` equals the number of w:r elements in the hyperlink.
#[test]
fn spec_hyperlink_runs_count_matches_source_runs() {
    // hyperlink-with-formatting has exactly 2 w:r children (bold + normal).
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hyperlink-with-formatting");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert_eq!(
        link.runs.len(),
        2,
        "hyperlink-with-formatting has 2 w:r elements; runs must capture each one"
    );
}

/// ISO 29500-1 §17.16.22 + formatting preservation invariant:
/// The first run of the formatted hyperlink is bold; its rpr_xml must be Some
/// and contain <w:b> so that serialization can restore the bold formatting.
#[test]
fn spec_hyperlink_run_rpr_preserved_for_bold_run() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hyperlink-with-formatting");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert!(
        !link.runs.is_empty(),
        "hyperlink must have at least one run"
    );

    let first_run = &link.runs[0];
    assert_eq!(first_run.text, "bold part", "first run text must match");
    assert!(
        first_run.rpr_xml.is_some(),
        "bold run must carry rpr_xml so serialization can restore <w:b>"
    );
    let rpr_str = String::from_utf8_lossy(first_run.rpr_xml.as_ref().unwrap());
    assert!(
        rpr_str.contains("<w:b") || rpr_str.contains("w:b"),
        "rpr_xml must contain the bold element; got: {rpr_str}"
    );
}

/// ISO 29500-1 §17.16.22 + formatting preservation invariant:
/// The second run of the formatted hyperlink has no extra formatting beyond the
/// hyperlink style. Its rpr_xml may be None (if no rPr element was present) or
/// must NOT contain <w:b> so that bold is not incorrectly applied.
#[test]
fn spec_hyperlink_second_run_not_bold() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "hyperlink-with-formatting");
    let links = collect_hyperlinks(&doc);

    assert!(!links.is_empty(), "should find at least one hyperlink");
    let link = &links[0];
    assert!(
        link.runs.len() >= 2,
        "hyperlink must have at least two runs"
    );

    let second_run = &link.runs[1];
    assert_eq!(
        second_run.text, " and normal part",
        "second run text must match"
    );
    if let Some(rpr_bytes) = &second_run.rpr_xml {
        let rpr_str = String::from_utf8_lossy(rpr_bytes);
        assert!(
            !rpr_str.contains("<w:b/>") && !rpr_str.contains("<w:b "),
            "second (non-bold) run must not have <w:b> in rpr_xml; got: {rpr_str}"
        );
    }
    // rpr_xml = None is also acceptable if the second run truly had no rPr element.
}
